1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	};
8	
9	type Item = { type: string };
10	type Step = { op: string; items?: Item[] };
11	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
12	
13	const computeQuotePremium = (items: Item[]): number => {
14	  if (items.length === 0) return PROCESSING_FEE;
15	  const basePremium = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
16	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
17	  return basePremium + firstInsuranceSurcharge + PROCESSING_FEE;
18	};
19	
20	export const runScenario = (input: unknown): unknown => {
21	  const scenario = input as Scenario;
22	  const results = scenario.steps.map((step) => {
23	    if (step.op === "quote") {
24	      return { premium: computeQuotePremium(step.items ?? []) };
25	    }
26	    return {};
27	  });
28	  return { results };
29	};
